import{_ as d,o as r,c as h,a2 as a}from"./chunks/framework.B72_uj9U.js";const c=JSON.parse('{"title":"化工行业供应商自评问卷（SAQ-CHEM-001）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/chemicals/saq.md","filePath":"zh/industry/chemicals/saq.md"}'),e={name:"zh/industry/chemicals/saq.md"};function _(o,t,l,n,s,b){return r(),h("div",null,[...t[0]||(t[0]=[a('<h1 id="化工行业供应商自评问卷-saq-chem-001" tabindex="-1">化工行业供应商自评问卷（SAQ-CHEM-001） <a class="header-anchor" href="#化工行业供应商自评问卷-saq-chem-001" aria-label="Permalink to &quot;化工行业供应商自评问卷（SAQ-CHEM-001）&quot;">​</a></h1><blockquote><p><strong>版本：</strong> 2025年版 · <strong>适用范围：</strong> 化工品制造商、危险品供应商、特种化学品分销商</p></blockquote><hr><p><strong>供应商信息</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>填写</th></tr></thead><tbody><tr><td>企业法人名称</td><td></td></tr><tr><td>生产/仓储地址</td><td></td></tr><tr><td>主要产品/化学品类别</td><td></td></tr><tr><td>危险化学品经营/生产许可证编号</td><td></td></tr><tr><td>ISO 14001 / ISO 45001 认证状态</td><td></td></tr><tr><td>填表人 / 职务 / 日期</td><td></td></tr></tbody></table><hr><h2 id="模块-ch1-过程安全-psm" tabindex="-1">模块 CH1　过程安全（PSM） <a class="header-anchor" href="#模块-ch1-过程安全-psm" aria-label="Permalink to &quot;模块 CH1　过程安全（PSM）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>CH1.1</td><td>是否建立了过程安全管理（PSM）体系，覆盖所有高危工艺？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH1.2</td><td>是否定期开展危险与可操作性研究（HAZOP）？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH1.3</td><td>是否有书面的紧急响应预案（含泄漏、爆炸、火灾场景）？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH1.4</td><td>过去5年内是否发生过重大工艺事故（泄漏、火灾、爆炸）？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH1.5</td><td>承压设备是否按期检验，有效期内？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-ch2-危险废物管理" tabindex="-1">模块 CH2　危险废物管理 <a class="header-anchor" href="#模块-ch2-危险废物管理" aria-label="Permalink to &quot;模块 CH2　危险废物管理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>CH2.1</td><td>是否建立危险废物管理台账（种类、产生量、去向）？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH2.2</td><td>危险废物是否全部交由持有《危险废物经营许可证》的单位处置？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH2.3</td><td>危险废物转移联单是否完整保存（≥3年）？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH2.4</td><td>是否有危险废物非法倾倒或超期存放的记录？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH2.5</td><td>危废暂存设施是否符合《危险废物贮存污染控制标准》？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-ch3-职业健康" tabindex="-1">模块 CH3　职业健康 <a class="header-anchor" href="#模块-ch3-职业健康" aria-label="Permalink to &quot;模块 CH3　职业健康&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>CH3.1</td><td>是否定期开展职业健康监测（针对接触有毒有害物质的岗位）？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH3.2</td><td>是否为所有接触危险化学品的岗位提供合规的个人防护设备（PPE）？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH3.3</td><td>新员工上岗前是否接受化学品安全培训？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH3.4</td><td>是否有化学品泄漏急救设施（洗眼站、淋浴设施）？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH3.5</td><td>过去3年是否有职业病确诊病例？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-ch4-出口管制-双重用途化学品" tabindex="-1">模块 CH4　出口管制（双重用途化学品） <a class="header-anchor" href="#模块-ch4-出口管制-双重用途化学品" aria-label="Permalink to &quot;模块 CH4　出口管制（双重用途化学品）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>不适用</th><th>备注</th></tr></thead><tbody><tr><td>CH4.1</td><td>贵司生产或销售的化学品是否属于双重用途物质（可转化为武器前体物）？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH4.2</td><td>是否建立最终用户核查程序（EUC），确认买方不会将产品用于非法用途？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH4.3</td><td>出口前是否核查买方是否在制裁名单/实体清单上？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH4.4</td><td>是否持有相关出口许可证（如适用）？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-ch5-环境排放" tabindex="-1">模块 CH5　环境排放 <a class="header-anchor" href="#模块-ch5-环境排放" aria-label="Permalink to &quot;模块 CH5　环境排放&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>CH5.1</td><td>废水是否经处理设施处理后达标排放，并有在线监测数据？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH5.2</td><td>废气是否安装处理设施（吸收塔、活性炭等），并有定期检测记录？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH5.3</td><td>过去3年是否有环保处罚记录（罚款、限产、停产）？</td><td></td><td></td><td></td><td></td></tr><tr><td>CH5.4</td><td>是否使用或生产《斯德哥尔摩公约》禁用的持久性有机污染物（POPs）？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><p><strong>授权签署</strong></p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>授权签署人</td><td>__________________</td></tr><tr><td>职务</td><td>__________________</td></tr><tr><td>日期</td><td>__________________</td></tr><tr><td>公章</td><td></td></tr></tbody></table>',23)])])}const C=d(e,[["render",_]]);export{c as __pageData,C as default};
